mapper.select:
SELECT UR.USER_ID AS userId, U.USER_NAME AS userName, UR.ROLE_ID AS roleId, R.ROLE_NAME AS roleName, UR.DESCRIPTION AS description FROM NB_USER_ROLES UR WITH (NOLOCK) LEFT JOIN NB_USERS U WITH (NOLOCK) ON UR.USER_ID = U.USER_ID LEFT JOIN NB_ROLES R WITH (NOLOCK) ON UR.ROLE_ID = R.ROLE_ID AND UR.SITE_ID = R.SITE_ID WHERE 1 = 1
AND UR.SITE_ID = #{siteId}
AND UR.USER_ID = #{userId}
ORDER BY UR.ROLE_ID ASC
